from itertools import count

# Count from 0, incrementing by 1
for i in count():
    print(i)
    if i >= 5:
        break  # Output: 0, 1, 2, 3, 4, 5

# Count starting from 10, incrementing by 2
for i in count(10, 2):
    print(i)
    if i >= 14:
        break  # Output: 10, 12, 14

from itertools import cycle

colors = ['red', 'green', 'blue']

for i, color in enumerate(cycle(colors)):
    print(color)
    if i >= 5:
        break  # Output: red, green, blue, red, green, blue

from functools import lru_cache

@lru_cache(maxsize=128)  # Cache up to 128 results
def factorial(n):
    if n <= 1:
        return 1
    return n * factorial(n - 1)

print(factorial(10))  # Output: 3628800 (computed and cached)
print(factorial(10))  # Output: 3628800 (cached, no re-computation)

from functools import lru_cache

@lru_cache(maxsize=None)  # Unlimited cache
def fibonacci(n):
    if n <= 1:
        return n
    return fibonacci(n - 1) + fibonacci(n - 2)

print(fibonacci(50))  # Output: 12586269025 (fast with caching!)

from functools import singledispatch

@singledispatch
def process(value):
    print(f"Default: {value}")

@process.register(int)
def _(value):
    print(f"Integer: {value * 2}")

@process.register(str)
def _(value):
    print(f"String: {value.upper()}")

process(5)     # Output: Integer: 10
process("hi")  # Output: String: HI
process(3.5)   # Output: Default: 3.5

from functools import wraps

def my_decorator(func):
    @wraps(func)  # Automatically calls update_wrapper
    def wrapper(*args, **kwargs):
        print(f"Calling {func.__name__}")
        return func(*args, **kwargs)
    return wrapper

@my_decorator
def greet(name):
    """Greet someone"""
    return f"Hello, {name}"

print(greet.__name__)  # Output: greet (preserved from original)
print(greet.__doc__)   # Output: Greet someone (preserved)
